import java.util.Arrays;
public class DoubleUp {
    public static void main(String[] args) {
        int[] original = {1, 2, 3};
        int[] copy = original;
        for (int i = 0; i < copy.length; i++) {
            copy[i] *= 2;
        }
        System.out.println(original[0]);  // prints 2, expected 1
    }
}
